//! Integration tests for the command pipeline against REAL Postgres.
//!
//! `#[sqlx::test(migrations = "../projections/migrations")]` provisions an
//! ephemeral DB and applies the full schema (event store + projections, incl.
//! the Phase-3 ballot/authority/occupancy/phase tables). Requires `DATABASE_URL`
//! (compose PG :5544); it never silently passes without a DB.
//!
//! The CENTERPIECE is `replacement_preserves_slot_history_and_transfers_authority`
//! — the unfixable User≠Slot call (doc 01): replacement keeps the slot's votes
//! and posts while moving authority from the outgoing to the incoming user.

use caps::Principal;
use commands::{
    audit_engine_snapshot_identity_boundary, audit_resolution_envelopes, handle,
    inspect_resolution_traces, load_engine_phase_input, load_engine_snapshot, Ack, Command,
    HostPromptDecision, Reject, ResolutionEnvelopeAuditEnvelope, ResolutionEnvelopeAuditStatus,
    VoteTarget,
};
use eventstore::{ActorId, EventInput};
use projections::{
    action_counters, action_grants, action_history, append_and_project, audit_rebuild,
    day_vote_outcomes, delayed_death_queues, host_prompts, investigation_memory, phase_state,
    player_info_results, player_notifications, player_notifications_for_slot, rebuild,
    sheriff_badges, slot_effects, slot_state, visit_history, votecount,
};
use sqlx::{Acquire, PgPool};
use std::collections::{BTreeMap, BTreeSet};
use std::fs;
use std::path::{Path, PathBuf};
use std::process::Command as ProcessCommand;
use std::time::{Duration, Instant};
use uuid::Uuid;

// ───────────────────────── helpers ─────────────────────────

fn user(id: &str) -> Principal {
    Principal::user(id)
}

/// Stand up a running game: host H creates it, adds slot S, assigns user A into
/// S, assigns a role, starts the game, and opens a Day phase. Returns (game_id).
async fn setup_game(pool: &PgPool, host: &str, slot: &str, occupant: &str) -> Uuid {
    setup_game_with_pack(pool, host, slot, occupant, "mafiascum").await
}

async fn setup_game_with_pack(
    pool: &PgPool,
    host: &str,
    slot: &str,
    occupant: &str,
    pack: &str,
) -> Uuid {
    let game = Uuid::new_v4();
    let h = user(host);

    handle(
        pool,
        &h,
        Command::CreateGame {
            game,
            pack: pack.into(),
        },
    )
    .await
    .expect("create game");
    handle(
        pool,
        &h,
        Command::AddSlot {
            game,
            slot: slot.into(),
        },
    )
    .await
    .expect("add slot");
    handle(
        pool,
        &h,
        Command::AssignSlot {
            game,
            slot: slot.into(),
            user: occupant.into(),
        },
    )
    .await
    .expect("assign slot");
    handle(
        pool,
        &h,
        Command::AssignRole {
            game,
            slot: slot.into(),
            role_key: "vanilla_townie".into(),
        },
    )
    .await
    .expect("assign role");
    handle(
        pool,
        &h,
        Command::StartGame {
            game,
            phase: "D01".into(),
        },
    )
    .await
    .expect("start game");
    game
}

/// Count of current ballots targeting `target` in `phase`.
async fn tally_for(pool: &PgPool, game: Uuid, phase: &str, target: &str) -> i64 {
    votecount(pool, game)
        .await
        .unwrap()
        .into_iter()
        .find(|r| r.phase_id == phase && r.candidate_slot == target)
        .map(|r| r.count)
        .unwrap_or(0)
}

fn assert_win_revealed_all_slots(slots: &[projections::SlotStateRow], context: &str) {
    assert!(
        slots
            .iter()
            .all(|slot| slot.role_revealed && slot.alignment_revealed),
        "{context}: WinReached should reveal all projected roles and alignments: {slots:?}"
    );
}

#[derive(Debug, Clone)]
struct TriggerGeneratedTraceExpectation<'a> {
    action_id: &'a str,
    on: &'a str,
    source_target: &'a str,
    source_actor: &'a str,
    source_cause: &'a str,
    produced_actor: &'a str,
    produced_target: &'a str,
    actor_filter: Option<serde_json::Value>,
    event_index: i64,
}

fn assert_trigger_generated_trace(
    trace: &domain::ResolutionTrace,
    expected: TriggerGeneratedTraceExpectation<'_>,
) {
    let generated = trace
        .generated
        .iter()
        .find(|generated| {
            generated.source == "Trigger" && generated.action_id == expected.action_id
        })
        .unwrap_or_else(|| {
            panic!(
                "ResolutionTrace should persist trigger generated row {}",
                expected.action_id
            )
        });
    assert_eq!(generated.actor, expected.produced_actor, "generated actor");
    assert_eq!(
        generated.targets,
        vec![expected.produced_target.to_string()],
        "generated targets"
    );
    assert_eq!(generated.detail["on"], expected.on, "trigger on");
    assert_eq!(
        generated.detail["source_target"], expected.source_target,
        "trigger source_target"
    );
    assert_eq!(
        generated.detail["source_actor"], expected.source_actor,
        "trigger source_actor"
    );
    assert_eq!(
        generated.detail["source_cause"], expected.source_cause,
        "trigger source_cause"
    );
    assert_eq!(
        generated.detail["produced_actor"], expected.produced_actor,
        "trigger produced_actor"
    );
    assert_eq!(
        generated.detail["produced_target"], expected.produced_target,
        "trigger produced_target"
    );
    assert_eq!(
        generated.detail["actor_filter"],
        expected.actor_filter.unwrap_or(serde_json::Value::Null),
        "trigger actor_filter"
    );
    assert_eq!(
        generated.detail["event_index"],
        serde_json::json!(expected.event_index),
        "trigger event_index"
    );
}

#[derive(Debug, Clone)]
struct DecisionTraceExpectation<'a> {
    stage: &'a str,
    source: &'a str,
    outcome: &'a str,
    detail: Vec<(&'a str, serde_json::Value)>,
}

fn assert_decision_trace(trace: &domain::ResolutionTrace, expected: DecisionTraceExpectation<'_>) {
    let decision = trace
        .decisions
        .iter()
        .find(|decision| {
            decision.stage == expected.stage
                && decision.source == expected.source
                && decision.outcome == expected.outcome
                && expected.detail.iter().all(|(key, value)| {
                    decision
                        .detail
                        .get(*key)
                        .is_some_and(|actual| actual == value)
                })
        })
        .unwrap_or_else(|| {
            panic!(
                "ResolutionTrace should persist decision {} from {} at {}",
                expected.outcome, expected.source, expected.stage
            )
        });
    for (key, value) in expected.detail {
        assert_eq!(
            decision.detail[key], value,
            "decision {} detail {key}",
            expected.outcome
        );
    }
}

fn assert_no_decision_trace(
    trace: &domain::ResolutionTrace,
    expected: DecisionTraceExpectation<'_>,
) {
    let forbidden = trace.decisions.iter().find(|decision| {
        decision.stage == expected.stage
            && decision.source == expected.source
            && decision.outcome == expected.outcome
            && expected.detail.iter().all(|(key, value)| {
                decision
                    .detail
                    .get(*key)
                    .is_some_and(|actual| actual == value)
            })
    });
    if let Some(decision) = forbidden {
        panic!(
            "ResolutionTrace should not persist decision {} from {} at {}: {:?}",
            expected.outcome, expected.source, expected.stage, decision
        );
    }
}

#[derive(Debug, Clone)]
struct InspectionDecisionExpectation<'a> {
    phase_id: &'a str,
    stage: &'a str,
    source: &'a str,
    outcome: &'a str,
    detail: serde_json::Value,
}

fn assert_anchored_inspection_decision(
    report: &commands::ResolutionTraceInspectionReport,
    expected: InspectionDecisionExpectation<'_>,
    context: &str,
) {
    check_anchored_inspection_decision(report, expected)
        .unwrap_or_else(|reason| panic!("{context}\n{reason}"));
}

fn check_anchored_inspection_decision(
    report: &commands::ResolutionTraceInspectionReport,
    expected: InspectionDecisionExpectation<'_>,
) -> Result<(), String> {
    let decision = match report
        .traces
        .iter()
        .filter(|trace| trace.phase_id == expected.phase_id && trace.applied_stream_seq.is_some())
        .flat_map(|trace| trace.decisions.iter())
        .find(|decision| {
            decision.applied_stream_seq.is_some()
                && decision.stage == expected.stage
                && decision.source == expected.source
                && decision.outcome == expected.outcome
        }) {
        Some(decision) => decision,
        None => {
            return Err(format!(
                "trace inspection should expose anchored decision {} from {} at {}",
                expected.outcome, expected.source, expected.stage
            ));
        }
    };
    if decision.detail != expected.detail {
        return Err(format!(
            "inspected decision {} detail expected {} got {}",
            expected.outcome, expected.detail, decision.detail
        ));
    }
    Ok(())
}

#[derive(Debug, Clone)]
struct InspectionGeneratedExpectation<'a> {
    phase_id: &'a str,
    action_id: &'a str,
    source: &'a str,
    actor: &'a str,
    targets: Vec<String>,
    detail: serde_json::Value,
}

fn check_anchored_inspection_generated(
    report: &commands::ResolutionTraceInspectionReport,
    expected: InspectionGeneratedExpectation<'_>,
) -> Result<(), String> {
    let generated = match report
        .traces
        .iter()
        .filter(|trace| trace.phase_id == expected.phase_id && trace.applied_stream_seq.is_some())
        .flat_map(|trace| trace.generated.iter())
        .find(|generated| {
            generated.applied_stream_seq.is_some()
                && generated.action_id == expected.action_id
                && generated.source == expected.source
                && generated.actor == expected.actor
                && generated.targets == expected.targets
        }) {
        Some(generated) => generated,
        None => {
            return Err(format!(
                "trace inspection should expose anchored generated row {} from {}",
                expected.action_id, expected.source
            ));
        }
    };
    if generated.detail != expected.detail {
        return Err(format!(
            "inspected generated row {} detail expected {} got {}",
            expected.action_id, expected.detail, generated.detail
        ));
    }
    Ok(())
}

fn assert_anchored_inspection_note(
    report: &commands::ResolutionTraceInspectionReport,
    phase_id: &str,
    expected_note: &str,
    context: &str,
) {
    check_anchored_inspection_note(report, phase_id, expected_note)
        .unwrap_or_else(|reason| panic!("{context}\n{reason}"));
}

fn check_anchored_inspection_note(
    report: &commands::ResolutionTraceInspectionReport,
    phase_id: &str,
    expected_note: &str,
) -> Result<(), String> {
    let note = match report
        .traces
        .iter()
        .filter(|trace| trace.phase_id == phase_id && trace.applied_stream_seq.is_some())
        .flat_map(|trace| trace.notes.iter())
        .find(|note| note.applied_stream_seq.is_some() && note.note == expected_note)
    {
        Some(note) => note,
        None => {
            return Err(format!(
                "trace inspection should expose anchored note {expected_note}"
            ));
        }
    };
    if note.note != expected_note {
        return Err(format!(
            "inspected note expected {expected_note} got {}",
            note.note
        ));
    }
    Ok(())
}

#[derive(Debug, Clone)]
struct TraceEdgeExpectation {
    kind: &'static str,
    from: &'static str,
    to: &'static str,
    detail: serde_json::Value,
}

fn assert_trace_edge(trace: &domain::ResolutionTrace, expected: TraceEdgeExpectation) {
    let edge = trace
        .edges
        .iter()
        .find(|edge| {
            edge.kind == expected.kind && edge.from == expected.from && edge.to == expected.to
        })
        .unwrap_or_else(|| {
            panic!(
                "ResolutionTrace should persist {} edge from {} to {}",
                expected.kind, expected.from, expected.to
            )
        });
    assert_eq!(
        edge.detail, expected.detail,
        "{} edge detail",
        expected.kind
    );
}

#[sqlx::test(migrations = "../projections/migrations")]
async fn host_phase_movement_respects_pack_cadence(pool: PgPool) {
    let game = Uuid::new_v4();
    let host = user("host_h");
    handle(
        &pool,
        &host,
        Command::CreateGame {
            game,
            pack: "default_open".into(),
        },
    )
    .await
    .unwrap();

    let err = handle(
        &pool,
        &host,
        Command::StartGame {
            game,
            phase: "T01".into(),
        },
    )
    .await
    .expect_err("default_open has no Twilight cadence");
    assert_eq!(err, Reject::InvalidTarget);
    assert!(
        phase_state(&pool, game).await.unwrap().is_none(),
        "rejected start must not create phase_state"
    );

    handle(
        &pool,
        &host,
        Command::StartGame {
            game,
            phase: "D01".into(),
        },
    )
    .await
    .expect("declared Day cadence is legal");
    assert_eq!(
        phase_state(&pool, game).await.unwrap().unwrap().phase_id,
        "D01"
    );

    let err = handle(
        &pool,
        &host,
        Command::OpenDayPhase {
            game,
            phase: "T01".into(),
        },
    )
    .await
    .expect_err("host advancement cannot use absent Twilight cadence");
    assert_eq!(err, Reject::InvalidTarget);
    assert_eq!(
        phase_state(&pool, game).await.unwrap().unwrap().phase_id,
        "D01",
        "rejected phase advance must not mutate phase_state"
    );

    let invalid_phase_events: i64 = sqlx::query_scalar(
        "SELECT COUNT(*) FROM events WHERE stream_id = $1 AND payload->>'phase_id' = 'T01'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    assert_eq!(
        invalid_phase_events, 0,
        "rejected phase movement must not append invalid phase events"
    );
}

#[sqlx::test(migrations = "../projections/migrations")]
async fn start_game_declares_mason_neighbor_private_channels(pool: PgPool) {
    let host = "host_h";
    let game = Uuid::new_v4();
    let h = user(host);

    handle(
        &pool,
        &h,
        Command::CreateGame {
            game,
            pack: "mafiascum".into(),
        },
    )
    .await
    .unwrap();
    for (slot, role) in [
        ("slot_1", "mason"),
        ("slot_2", "mason"),
        ("slot_3", "neighbor"),
        ("slot_4", "neighbor"),
        ("slot_5", "vanilla_townie"),
    ] {
        handle(
            &pool,
            &h,
            Command::AddSlot {
                game,
                slot: slot.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignRole {
                game,
                slot: slot.into(),
                role_key: role.into(),
            },
        )
        .await
        .unwrap();
    }

    handle(
        &pool,
        &h,
        Command::StartGame {
            game,
            phase: "D01".into(),
        },
    )
    .await
    .expect("start declares setup private channels");

    let declarations = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'PrivateChannelDeclared' \
         ORDER BY payload->>'channel_id'",
    )
    .bind(game)
    .fetch_all(&pool)
    .await
    .unwrap();
    assert_eq!(declarations.len(), 2);
    assert_eq!(declarations[0]["channel_id"], "private:mason");
    assert_eq!(declarations[0]["kind"], "Mason");
    assert_eq!(declarations[0]["reveals_alignment"], "Town");
    assert_eq!(declarations[0]["members"][0]["slot_id"], "slot_1");
    assert_eq!(declarations[0]["members"][1]["slot_id"], "slot_2");
    assert_eq!(declarations[1]["channel_id"], "private:neighbor");
    assert_eq!(declarations[1]["kind"], "Neighbor");
    assert_eq!(declarations[1]["reveals_alignment"], "None");
    assert_eq!(declarations[1]["members"][0]["slot_id"], "slot_3");
    assert_eq!(declarations[1]["members"][1]["slot_id"], "slot_4");

    let members = projections::private_channel_members(&pool, game)
        .await
        .expect("private channel projection");
    let summary = members
        .iter()
        .map(|member| {
            (
                member.channel_id.as_str(),
                member.kind.as_str(),
                member.slot_id.as_str(),
                member.role_key.as_str(),
                member.reveals_alignment.as_str(),
            )
        })
        .collect::<Vec<_>>();
    assert_eq!(
        summary,
        vec![
            ("private:mason", "Mason", "slot_1", "mason", "Town"),
            ("private:mason", "Mason", "slot_2", "mason", "Town"),
            ("private:neighbor", "Neighbor", "slot_3", "neighbor", "None"),
            ("private:neighbor", "Neighbor", "slot_4", "neighbor", "None"),
        ]
    );
    assert!(
        projections::thread_view(&pool, game, None, 50)
            .await
            .unwrap()
            .posts
            .is_empty(),
        "private channel metadata must not leak into public thread_view"
    );

    let members_before = serde_json::to_string(&members).unwrap();
    rebuild(&pool, game).await.expect("projection rebuild");
    assert_eq!(
        members_before,
        serde_json::to_string(
            &projections::private_channel_members(&pool, game)
                .await
                .unwrap()
        )
        .unwrap(),
        "private channel membership rebuild must be deterministic"
    );
}

#[sqlx::test(migrations = "../projections/migrations")]
async fn encryptor_declares_and_revokes_mafia_day_chat(pool: PgPool) {
    let host = "host_h";
    let game = Uuid::new_v4();
    let h = user(host);

    handle(
        &pool,
        &h,
        Command::CreateGame {
            game,
            pack: "mafiascum".into(),
        },
    )
    .await
    .unwrap();
    for (slot, occupant, role) in [
        ("slot_1", "encryptor_user_1", "encryptor"),
        ("slot_2", "encryptor_user_2", "mafia_goon"),
        ("slot_3", "encryptor_user_3", "vanilla_townie"),
        ("slot_4", "encryptor_user_4", "vanilla_townie"),
        ("slot_5", "encryptor_user_5", "vanilla_townie"),
        ("slot_6", "encryptor_user_6", "traitor"),
    ] {
        handle(
            &pool,
            &h,
            Command::AddSlot {
                game,
                slot: slot.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignSlot {
                game,
                slot: slot.into(),
                user: occupant.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignRole {
                game,
                slot: slot.into(),
                role_key: role.into(),
            },
        )
        .await
        .unwrap();
    }

    handle(
        &pool,
        &h,
        Command::StartGame {
            game,
            phase: "D01".into(),
        },
    )
    .await
    .expect("start declares Encryptor-gated mafia day chat");

    let declaration = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'PrivateChannelDeclared' \
         AND payload->>'channel_id' = 'private:mafia_day_chat'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    assert_eq!(declaration["kind"], "FactionDayChat");
    assert_eq!(
        declaration["member_alignments"],
        serde_json::json!(["mafia"])
    );
    assert_eq!(
        declaration["enabled_by_roles"],
        serde_json::json!(["encryptor"])
    );
    assert_eq!(
        declaration["excluded_roles"],
        serde_json::json!(["traitor"])
    );
    assert_eq!(declaration["active_while_source_alive"], true);
    assert_eq!(declaration["source_slots"], serde_json::json!(["slot_1"]));
    assert_eq!(declaration["members"].as_array().unwrap().len(), 2);
    assert_eq!(declaration["members"][0]["slot_id"], "slot_1");
    assert_eq!(declaration["members"][0]["role_key"], "encryptor");
    assert_eq!(declaration["members"][1]["slot_id"], "slot_2");
    assert_eq!(declaration["members"][1]["role_key"], "mafia_goon");

    let members = projections::private_channel_members(&pool, game)
        .await
        .expect("private channel projection");
    let faction_members = members
        .iter()
        .filter(|member| member.channel_id == "private:mafia_day_chat")
        .map(|member| {
            (
                member.kind.as_str(),
                member.slot_id.as_str(),
                member.role_key.as_str(),
                member.reveals_alignment.as_str(),
                member.source.as_str(),
            )
        })
        .collect::<Vec<_>>();
    assert_eq!(
        faction_members,
        vec![
            (
                "FactionDayChat",
                "slot_1",
                "encryptor",
                "None",
                "pack.private_channels.mafia_day_chat"
            ),
            (
                "FactionDayChat",
                "slot_2",
                "mafia_goon",
                "None",
                "pack.private_channels.mafia_day_chat"
            ),
        ]
    );

    for (voter_user, voter_slot) in [
        ("encryptor_user_3", "slot_3"),
        ("encryptor_user_4", "slot_4"),
        ("encryptor_user_5", "slot_5"),
        ("encryptor_user_6", "slot_6"),
    ] {
        handle(
            &pool,
            &user(voter_user),
            Command::SubmitVote {
                game,
                actor_slot: voter_slot.into(),
                target: VoteTarget::Slot("slot_1".into()),
            },
        )
        .await
        .unwrap_or_else(|err| panic!("{voter_slot} vote against Encryptor failed: {err:?}"));
    }

    let ack = handle(&pool, &h, Command::ResolvePhase { game, seed: 771101 })
        .await
        .expect("host resolves Encryptor lynch and revokes day chat");
    assert_eq!(
        ack.stream_seqs.len(),
        4,
        "Encryptor lynch appends ResolutionApplied, ResolutionTrace, PrivateChannelRevoked, and ThreadLocked atomically"
    );
    let applied_payload = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionApplied' \
         AND payload->>'phase_id' = 'D01'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    let applied = domain::validate_resolution_json(&applied_payload, domain::RESULT_VERSION)
        .expect("valid Encryptor lynch result");
    assert!(
        applied.events.iter().any(|indexed| matches!(
            &indexed.event,
            domain::InnerEvent::PlayerKilled { slot_id, cause, .. }
                if slot_id == "slot_1" && cause == "day_vote"
        )),
        "expected Encryptor day-vote death, got {:#?}",
        applied.events
    );

    let revocation = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'PrivateChannelRevoked' \
         AND payload->>'channel_id' = 'private:mafia_day_chat'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    assert_eq!(revocation["kind"], "FactionDayChat");
    assert_eq!(revocation["reason"], "source_role_not_alive");
    assert_eq!(revocation["source"], "pack.private_channels.mafia_day_chat");

    let members_after = projections::private_channel_members(&pool, game)
        .await
        .expect("private channel projection after revocation");
    assert!(
        members_after
            .iter()
            .all(|member| member.channel_id != "private:mafia_day_chat"),
        "Encryptor day chat should be revoked after the last Encryptor dies"
    );

    let members_after_json = serde_json::to_string(&members_after).unwrap();
    rebuild(&pool, game).await.expect("projection rebuild");
    assert_eq!(
        members_after_json,
        serde_json::to_string(
            &projections::private_channel_members(&pool, game)
                .await
                .unwrap()
        )
        .unwrap(),
        "Encryptor private-channel revocation rebuild must be deterministic"
    );
}

#[sqlx::test(migrations = "../projections/migrations")]
async fn start_game_declares_mafia_universe_mason_neighbor_private_channels(pool: PgPool) {
    let host = "host_h";
    let game = Uuid::new_v4();
    let h = user(host);

    handle(
        &pool,
        &h,
        Command::CreateGame {
            game,
            pack: "mafia_universe".into(),
        },
    )
    .await
    .unwrap();
    for (slot, role) in [
        ("slot_1", "mason"),
        ("slot_2", "mason"),
        ("slot_3", "neighbor"),
        ("slot_4", "neighbor"),
        ("slot_5", "town_vanilla"),
    ] {
        handle(
            &pool,
            &h,
            Command::AddSlot {
                game,
                slot: slot.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignRole {
                game,
                slot: slot.into(),
                role_key: role.into(),
            },
        )
        .await
        .unwrap();
    }

    handle(
        &pool,
        &h,
        Command::StartGame {
            game,
            phase: "D01".into(),
        },
    )
    .await
    .expect("start declares Mafia Universe setup private channels");

    let declarations = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'PrivateChannelDeclared' \
         ORDER BY payload->>'channel_id'",
    )
    .bind(game)
    .fetch_all(&pool)
    .await
    .unwrap();
    assert_eq!(declarations.len(), 2);
    assert_eq!(declarations[0]["channel_id"], "private:mason");
    assert_eq!(declarations[0]["kind"], "Mason");
    assert_eq!(declarations[0]["roles"], serde_json::json!(["mason"]));
    assert_eq!(declarations[0]["reveals_alignment"], "Town");
    assert_eq!(declarations[0]["source"], "pack.private_channels.mason");
    assert_eq!(declarations[0]["members"][0]["slot_id"], "slot_1");
    assert_eq!(declarations[0]["members"][0]["role_key"], "mason");
    assert_eq!(declarations[0]["members"][1]["slot_id"], "slot_2");
    assert_eq!(declarations[1]["channel_id"], "private:neighbor");
    assert_eq!(declarations[1]["kind"], "Neighbor");
    assert_eq!(declarations[1]["roles"], serde_json::json!(["neighbor"]));
    assert_eq!(declarations[1]["reveals_alignment"], "None");
    assert_eq!(declarations[1]["source"], "pack.private_channels.neighbor");
    assert_eq!(declarations[1]["members"][0]["slot_id"], "slot_3");
    assert_eq!(declarations[1]["members"][0]["role_key"], "neighbor");
    assert_eq!(declarations[1]["members"][1]["slot_id"], "slot_4");

    let members = projections::private_channel_members(&pool, game)
        .await
        .expect("Mafia Universe private channel projection");
    let summary = members
        .iter()
        .map(|member| {
            (
                member.channel_id.as_str(),
                member.kind.as_str(),
                member.slot_id.as_str(),
                member.role_key.as_str(),
                member.reveals_alignment.as_str(),
                member.source.as_str(),
            )
        })
        .collect::<Vec<_>>();
    assert_eq!(
        summary,
        vec![
            (
                "private:mason",
                "Mason",
                "slot_1",
                "mason",
                "Town",
                "pack.private_channels.mason"
            ),
            (
                "private:mason",
                "Mason",
                "slot_2",
                "mason",
                "Town",
                "pack.private_channels.mason"
            ),
            (
                "private:neighbor",
                "Neighbor",
                "slot_3",
                "neighbor",
                "None",
                "pack.private_channels.neighbor"
            ),
            (
                "private:neighbor",
                "Neighbor",
                "slot_4",
                "neighbor",
                "None",
                "pack.private_channels.neighbor"
            ),
        ]
    );
    assert!(
        projections::thread_view(&pool, game, None, 50)
            .await
            .unwrap()
            .posts
            .is_empty(),
        "Mafia Universe private channel metadata must not leak into public thread_view"
    );

    let members_before = serde_json::to_string(&members).unwrap();
    rebuild(&pool, game).await.expect("projection rebuild");
    assert_eq!(
        members_before,
        serde_json::to_string(
            &projections::private_channel_members(&pool, game)
                .await
                .unwrap()
        )
        .unwrap(),
        "Mafia Universe private channel membership rebuild must be deterministic"
    );
}

#[sqlx::test(migrations = "../projections/migrations")]
async fn host_resolve_phase_carries_mafia_universe_town_strongman_pierce(pool: PgPool) {
    let host = user("host_mu_town_strongman");
    let game = Uuid::new_v4();

    handle(
        &pool,
        &host,
        Command::CreateGame {
            game,
            pack: "mafia_universe".into(),
        },
    )
    .await
    .unwrap();
    for (slot, occupant, role) in [
        ("slot_1", "mu_town_strongman_user", "town_strongman"),
        ("slot_2", "mu_town_doctor_user", "town_doctor"),
        ("slot_3", "mu_town_vanilla_user", "town_vanilla"),
        ("slot_4", "mu_mafia_goon_user", "mafia_goon"),
    ] {
        handle(
            &pool,
            &host,
            Command::AddSlot {
                game,
                slot: slot.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &host,
            Command::AssignSlot {
                game,
                slot: slot.into(),
                user: occupant.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &host,
            Command::AssignRole {
                game,
                slot: slot.into(),
                role_key: role.into(),
            },
        )
        .await
        .unwrap();
    }
    handle(
        &pool,
        &host,
        Command::StartGame {
            game,
            phase: "N01".into(),
        },
    )
    .await
    .unwrap();

    handle(
        &pool,
        &user("mu_town_strongman_user"),
        Command::SubmitAction {
            game,
            action_id: "mu_town_strongman_001".into(),
            actor_slot: "slot_1".into(),
            template_id: "strongman_kill".into(),
            targets: vec!["slot_3".into()],
            grant_id: None,
        },
    )
    .await
    .expect("Town Strongman can submit strongman_kill from Mafia Universe pack");
    handle(
        &pool,
        &user("mu_town_doctor_user"),
        Command::SubmitAction {
            game,
            action_id: "mu_doctor_001".into(),
            actor_slot: "slot_2".into(),
            template_id: "doctor_protect".into(),
            targets: vec!["slot_3".into()],
            grant_id: None,
        },
    )
    .await
    .unwrap();

    let ack = handle(&pool, &host, Command::ResolvePhase { game, seed: 971004 })
        .await
        .expect("host resolves Mafia Universe Town Strongman pierce");
    assert_eq!(
        ack.stream_seqs.len(),
        3,
        "ResolvePhase should append applied results, trace, and phase lock atomically"
    );

    let applied_payload = resolution_payload(&pool, game, "N01", 971004).await;
    let applied = domain::validate_resolution_json(&applied_payload, domain::RESULT_VERSION)
        .expect("Mafia Universe Town Strongman ResolutionApplied validates");
    assert!(applied.events.iter().any(|indexed| matches!(
        &indexed.event,
        domain::InnerEvent::PlayerKilled {
            slot_id,
            cause,
            attackers,
            unstoppable,
            ..
        } if slot_id == "slot_3"
            && cause == "strongman_kill"
            && attackers == &vec!["slot_1".to_string()]
            && *unstoppable
    )));
    assert!(
        !applied.events.iter().any(|indexed| matches!(
            &indexed.event,
            domain::InnerEvent::PlayerSaved { slot_id, .. } if slot_id == "slot_3"
        )),
        "doctor protection must be bypassed by Town Strongman pierce"
    );

    let slots = slot_state(&pool, game).await.unwrap();
    assert!(
        !slots
            .iter()
            .find(|slot| slot.slot_id == "slot_3")
            .unwrap()
            .alive,
        "Town Strongman target should be dead in projections"
    );
    for slot_id in ["slot_1", "slot_2", "slot_4"] {
        assert!(
            slots
                .iter()
                .find(|slot| slot.slot_id == slot_id)
                .unwrap()
                .alive,
            "{slot_id} should remain alive after Town Strongman pierce"
        );
    }
    let audit = audit_resolution_envelopes(&pool, game)
        .await
        .expect("Mafia Universe Town Strongman audit_resolution");
    assert!(
        audit.ok,
        "Mafia Universe Town Strongman resolution audit drifted: {audit:?}"
    );

    let slots_before = serde_json::to_string(&slots).unwrap();
    rebuild(&pool, game).await.expect("projection rebuild");
    assert_eq!(
        slots_before,
        serde_json::to_string(&slot_state(&pool, game).await.unwrap()).unwrap(),
        "slot_state rebuild must preserve Mafia Universe Town Strongman pierce"
    );
}

