    assert!(
        audit.ok,
        "Mafia Universe alignment-reveal audit drifted: {audit:?}"
    );
    assert_eq!(audit.audited, 1);
    assert_eq!(audit.skipped, 0);

    let projected_before = serde_json::to_string(&projected).unwrap();
