        generated_handle_or_shrink(
            &pool,
            &host,
            Command::CreateGame {
                game,
                pack: "mafia_universe".into(),
            },
            &shrink_stem,
            &fixture_json,
            &summary,
            "create Mafia Universe generated game failed",
        )
        .await;
        for (slot, role) in &case.roster {
            generated_handle_or_shrink(
                &pool,
                &host,
                Command::AddSlot {
                    game,
                    slot: slot.clone(),
                },
                &shrink_stem,
                &fixture_json,
                &summary,
                format!("add {slot} failed"),
            )
            .await;
            generated_handle_or_shrink(
                &pool,
                &host,
                Command::AssignSlot {
                    game,
                    slot: slot.clone(),
                    user: format!("mafia_universe_ita_seed_{seed}_user_{}", slot_number(slot)),
                },
                &shrink_stem,
                &fixture_json,
                &summary,
                format!("assign {slot} failed"),
            )
            .await;
            generated_handle_or_shrink(
                &pool,
                &host,
                Command::AssignRole {
                    game,
                    slot: slot.clone(),
                    role_key: role.clone(),
                },
                &shrink_stem,
                &fixture_json,
                &summary,
                format!("role {slot} failed"),
            )
            .await;
        }
        generated_handle_or_shrink(
            &pool,
            &host,
            Command::StartGame {
                game,
                phase: "D01".into(),
            },
            &shrink_stem,
            &fixture_json,
            &summary,
            "start Mafia Universe D01 failed",
        )
        .await;

        for action in &case.actions {
            generated_handle_or_shrink(
                &pool,
                &Principal::user(format!(
                    "mafia_universe_ita_seed_{seed}_user_{}",
                    slot_number(&action.actor_slot)
                )),
                Command::SubmitAction {
                    game,
                    action_id: action.action_id.clone(),
                    actor_slot: action.actor_slot.clone(),
                    template_id: action.template_id.clone(),
                    targets: action.targets.clone(),
                    grant_id: None,
                },
                &shrink_stem,
                &fixture_json,
                &summary,
                format!(
                    "submit {} for {} failed",
                    action.template_id, action.actor_slot
                ),
            )
            .await;
        }

        let ack = match handle(
            &pool,
            &host,
            Command::ResolvePhase {
                game,
                seed: resolver_seed,
            },
        )
        .await
        {
            Ok(ack) => ack,
            Err(err) => {
                panic!(
                    "{}",
                    generated_shrink_failure_message(
                        &pool,
                        &shrink_stem,
                        &fixture_json,
                        &summary,
                        format!("resolve Mafia Universe ITA graph failed: {err}"),
                    )
                    .await
                )
            }
        };
