async fn resolution_payload(
    pool: &PgPool,
    game: Uuid,
    phase_id: &str,
    seed: u64,
) -> serde_json::Value {
    sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionApplied' \
         AND payload->>'phase_id' = $2",
    )
    .bind(game)
    .bind(phase_id)
    .fetch_one(pool)
    .await
    .unwrap_or_else(|err| panic!("seed {seed}: fetch {phase_id} ResolutionApplied failed: {err}"))
}

fn slot_number(slot: &str) -> usize {
    slot.strip_prefix("slot_")
        .and_then(|number| number.parse().ok())
        .expect("slot_N")
}

fn choose_target<'a>(rng: &mut DeterministicRng, slots: &'a [&'a str], actor: &str) -> &'a str {
    let candidates: Vec<_> = slots
        .iter()
        .copied()
        .filter(|slot| *slot != actor)
        .collect();
    candidates[rng.index(candidates.len())]
}

fn choose_target_pair<'a>(
    rng: &mut DeterministicRng,
    slots: &'a [&'a str],
    actor: &str,
) -> Vec<&'a str> {
    let first = choose_target(rng, slots, actor);
    let candidates: Vec<_> = slots
        .iter()
        .copied()
        .filter(|slot| *slot != actor && *slot != first)
        .collect();
    let second = candidates[rng.index(candidates.len())];
    vec![first, second]
}

#[sqlx::test(migrations = "../projections/migrations")]
async fn host_resolve_phase_carries_super_saint_lynch_trigger(pool: PgPool) {
    let host = "host_h";
    let game = Uuid::new_v4();
    let h = user(host);

    handle(
        &pool,
        &h,
        Command::CreateGame {
            game,
            pack: "mafiascum".into(),
        },
    )
    .await
    .unwrap();
    for (slot, occupant, role) in [
        ("slot_1", "user_1", "super_saint"),
        ("slot_2", "user_2", "vanilla_townie"),
        ("slot_3", "user_3", "vanilla_townie"),
        ("slot_4", "user_4", "vanilla_townie"),
        ("slot_5", "user_5", "mafia_goon"),
        ("slot_6", "user_6", "vanilla_townie"),
        ("slot_7", "user_7", "mafia_goon"),
    ] {
        handle(
            &pool,
            &h,
            Command::AddSlot {
                game,
                slot: slot.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignSlot {
                game,
                slot: slot.into(),
                user: occupant.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignRole {
                game,
                slot: slot.into(),
                role_key: role.into(),
            },
        )
        .await
        .unwrap();
    }
    handle(
        &pool,
        &h,
        Command::StartGame {
            game,
            phase: "D01".into(),
        },
    )
    .await
    .unwrap();

    for (user_id, actor_slot) in [
        ("user_3", "slot_3"),
        ("user_4", "slot_4"),
        ("user_5", "slot_5"),
        ("user_2", "slot_2"),
    ] {
        handle(
            &pool,
            &user(user_id),
            Command::SubmitVote {
                game,
                actor_slot: actor_slot.into(),
                target: VoteTarget::Slot("slot_1".into()),
            },
        )
        .await
        .unwrap();
    }
    handle(&pool, &h, Command::ResolvePhase { game, seed: 7401 })
        .await
        .expect("host resolves Super-Saint lynch trigger");

    let applied_payload = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionApplied' \
         AND payload->>'phase_id' = 'D01'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    let applied = domain::validate_resolution_json(&applied_payload, domain::RESULT_VERSION)
        .expect("valid Super-Saint result");
    assert!(applied.events.iter().any(|indexed| matches!(
        &indexed.event,
        domain::InnerEvent::DayVoteOutcome(outcome)
            if outcome.winner.as_deref() == Some("slot_1")
    )));
    assert!(applied.events.iter().any(|indexed| matches!(
        &indexed.event,
        domain::InnerEvent::Trigger {
            trigger_id,
            payload,
        } if trigger_id == "super_saint_retaliates"
            && payload["on"] == "Lynch"
            && payload["source_target"] == "slot_1"
            && payload["source_actor"] == "slot_2"
            && payload["source_cause"] == "lynch"
            && payload["produced_actor"] == "slot_1"
            && payload["produced_target"] == "slot_2"
    )));
    assert!(applied.events.iter().any(|indexed| matches!(
        &indexed.event,
        domain::InnerEvent::PlayerKilled { slot_id, cause, .. }
            if slot_id == "slot_1" && cause == "day_vote"
    )));
    assert!(applied.events.iter().any(|indexed| matches!(
        &indexed.event,
        domain::InnerEvent::PlayerKilled {
            slot_id,
            cause,
            attackers,
            unstoppable,
            ..
        } if slot_id == "slot_2"
            && cause == "super_saint_retaliates"
            && attackers == &vec!["slot_1".to_string()]
            && !*unstoppable
    )));

    let trace_payload = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionTrace' \
         AND payload->>'phase_id' = 'D01'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    let trace = domain::validate_trace_json(&trace_payload, domain::TRACE_VERSION)
        .expect("valid Super-Saint trace");
    assert!(
        trace
            .notes
            .iter()
            .any(|note| note == "trigger super_saint_retaliates emitted at event_index 6"),
        "Super-Saint day trigger should persist trace note"
    );
    assert_trigger_generated_trace(
        &trace,
        TriggerGeneratedTraceExpectation {
            action_id: "super_saint_retaliates",
            on: "Lynch",
            source_target: "slot_1",
            source_actor: "slot_2",
            source_cause: "lynch",
            produced_actor: "slot_1",
            produced_target: "slot_2",
            actor_filter: None,
            event_index: 6,
        },
    );

    let slots = slot_state(&pool, game).await.unwrap();
    assert!(
        !slots
            .iter()
            .find(|slot| slot.slot_id == "slot_1")
            .unwrap()
            .alive,
        "lynched Super-Saint should be dead"
    );
    assert!(
        !slots
            .iter()
            .find(|slot| slot.slot_id == "slot_2")
            .unwrap()
            .alive,
        "execution-responsible voter should be killed by Super-Saint trigger"
    );

    let slots_before = serde_json::to_string(&slots).unwrap();
    rebuild(&pool, game).await.expect("projection rebuild");
    assert_eq!(
        slots_before,
        serde_json::to_string(&slot_state(&pool, game).await.unwrap()).unwrap(),
        "slot_state rebuild must preserve Super-Saint lynch trigger outcome"
    );
    let trace_after_rebuild = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionTrace' \
         AND payload->>'phase_id' = 'D01'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    assert_eq!(
        trace_payload, trace_after_rebuild,
        "projection rebuild must not rewrite Super-Saint lynch trigger trace envelope"
    );
}

