#[sqlx::test(migrations = "../projections/migrations")]
async fn host_resolve_phase_carries_chinese_wolf_faction_vote_policy(pool: PgPool) {
    let same_target_game = Uuid::new_v4();
    let same_target_host = user("host_wolf_faction_same_target");
    setup_chinese_wolf_faction_vote_game(&pool, same_target_game, &same_target_host, "same").await;
    submit_chinese_wolf_kill_vote(
        &pool,
        same_target_game,
        "same_user_1",
        "slot_1",
        "wolfkill_001",
        "slot_3",
    )
    .await;
    submit_chinese_wolf_kill_vote(
        &pool,
        same_target_game,
        "same_user_2",
        "slot_2",
        "wolfkill_002",
        "slot_3",
    )
    .await;

    let ack = handle(
        &pool,
        &same_target_host,
        Command::ResolvePhase {
            game: same_target_game,
            seed: 930601,
        },
    )
    .await
    .expect("host resolves same-target wolf faction vote");
    assert_eq!(
        ack.stream_seqs.len(),
        3,
        "ResolvePhase should append applied results, trace, and phase lock atomically"
    );

    let same_payload = resolution_payload(&pool, same_target_game, "N01", 930601).await;
    let same_applied =
        domain::validate_resolution_json(&same_payload, domain::RESULT_VERSION).unwrap();
    assert!(same_applied.events.iter().any(|indexed| matches!(
        &indexed.event,
        domain::InnerEvent::ActionInterfered { actor, reason }
            if actor == "slot_2" && reason == "faction_vote_superseded"
    )));
    assert!(same_applied.events.iter().any(|indexed| matches!(
        &indexed.event,
        domain::InnerEvent::PlayerKilled {
            slot_id,
            cause,
            attackers,
            unstoppable,
            ..
        } if slot_id == "slot_3"
            && cause == "wolf_night_kill"
            && attackers == &vec!["slot_1".to_string()]
            && !*unstoppable
    )));
    assert!(
        !same_applied.events.iter().any(|indexed| matches!(
            &indexed.event,
            domain::InnerEvent::PlayerKilled { slot_id, .. } if slot_id == "slot_4"
        )),
        "same-target faction vote should not execute both wolf submissions"
    );

    let same_slots = slot_state(&pool, same_target_game).await.unwrap();
    assert!(
        !same_slots
            .iter()
            .find(|slot| slot.slot_id == "slot_3")
            .unwrap()
            .alive,
        "same-target faction vote should kill the chosen target through projections"
    );
    for slot_id in ["slot_1", "slot_2", "slot_4", "slot_5", "slot_6"] {
        assert!(
            same_slots
                .iter()
                .find(|slot| slot.slot_id == slot_id)
                .unwrap()
                .alive,
            "{slot_id} should remain alive after same-target faction vote"
        );
    }
    let same_resolution_audit = audit_resolution_envelopes(&pool, same_target_game)
        .await
        .expect("same-target wolf faction vote audit_resolution");
    assert!(
        same_resolution_audit.ok,
        "same-target wolf faction vote resolution audit drifted: {same_resolution_audit:?}"
    );
    let same_projection_audit = audit_rebuild(&pool, same_target_game)
        .await
        .expect("same-target wolf faction vote audit_rebuild");
    assert!(
        same_projection_audit.ok,
        "same-target wolf faction vote projection rebuild drifted: {same_projection_audit:?}"
    );

    let tie_game = Uuid::new_v4();
    let tie_host = user("host_wolf_faction_tie");
    setup_chinese_wolf_faction_vote_game(&pool, tie_game, &tie_host, "tie").await;
    submit_chinese_wolf_kill_vote(
        &pool,
        tie_game,
        "tie_user_1",
        "slot_1",
        "wolfkill_001",
        "slot_3",
    )
    .await;
    submit_chinese_wolf_kill_vote(
        &pool,
        tie_game,
        "tie_user_2",
        "slot_2",
        "wolfkill_002",
        "slot_4",
    )
    .await;

    let ack = handle(
        &pool,
        &tie_host,
        Command::ResolvePhase {
            game: tie_game,
            seed: 930602,
        },
    )
    .await
    .expect("host resolves split wolf faction vote");
    assert_eq!(
        ack.stream_seqs.len(),
        3,
        "ResolvePhase should append tied faction vote envelopes atomically"
    );

    let tie_payload = resolution_payload(&pool, tie_game, "N01", 930602).await;
    let tie_applied =
        domain::validate_resolution_json(&tie_payload, domain::RESULT_VERSION).unwrap();
    for actor in ["slot_1", "slot_2"] {
        assert!(
            tie_applied.events.iter().any(|indexed| matches!(
                &indexed.event,
                domain::InnerEvent::ActionInterfered { actor: event_actor, reason }
                    if event_actor == actor && reason == "faction_vote_tie"
            )),
            "{actor} should be blocked by split wolf faction vote"
        );
    }
    assert!(
        !tie_applied
            .events
            .iter()
            .any(|indexed| matches!(&indexed.event, domain::InnerEvent::PlayerKilled { .. })),
        "split wolf faction vote with BlockAll tie policy should not kill anyone"
    );
    let tie_slots = slot_state(&pool, tie_game).await.unwrap();
    for slot_id in ["slot_1", "slot_2", "slot_3", "slot_4", "slot_5", "slot_6"] {
        assert!(
            tie_slots
                .iter()
                .find(|slot| slot.slot_id == slot_id)
                .unwrap()
                .alive,
            "{slot_id} should remain alive after tied faction vote"
        );
    }
    let tie_resolution_audit = audit_resolution_envelopes(&pool, tie_game)
        .await
        .expect("tied wolf faction vote audit_resolution");
    assert!(
        tie_resolution_audit.ok,
        "tied wolf faction vote resolution audit drifted: {tie_resolution_audit:?}"
    );
    let tie_projection_audit = audit_rebuild(&pool, tie_game)
        .await
        .expect("tied wolf faction vote audit_rebuild");
    assert!(
        tie_projection_audit.ok,
        "tied wolf faction vote projection rebuild drifted: {tie_projection_audit:?}"
    );
}

