#[sqlx::test(migrations = "../projections/migrations")]
async fn host_resolve_phase_carries_mafia_universe_poison_cure_and_delayed_death(pool: PgPool) {
    let host = "host_mu_poison";
    let game = Uuid::new_v4();
    let h = user(host);

    handle(
        &pool,
        &h,
        Command::CreateGame {
            game,
            pack: "mafia_universe".into(),
        },
    )
    .await
    .unwrap();
    for (slot, occupant, role) in [
        ("slot_1", "mu_poison_user_1", "town_poisoner"),
        ("slot_2", "mu_poison_user_2", "town_poison_doctor"),
        ("slot_3", "mu_poison_user_3", "town_vanilla"),
        ("slot_4", "mu_poison_user_4", "town_vanilla"),
        ("slot_5", "mu_poison_user_5", "town_vanilla"),
        ("slot_6", "mu_poison_user_6", "mafia_goon"),
    ] {
        handle(
            &pool,
            &h,
            Command::AddSlot {
                game,
                slot: slot.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignSlot {
                game,
                slot: slot.into(),
                user: occupant.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignRole {
                game,
                slot: slot.into(),
                role_key: role.into(),
            },
        )
        .await
        .unwrap();
    }
    handle(
        &pool,
        &h,
        Command::StartGame {
            game,
            phase: "N01".into(),
        },
    )
    .await
    .unwrap();

    handle(
        &pool,
        &user("mu_poison_user_1"),
        Command::SubmitAction {
            game,
            action_id: "mu_poison_n01".into(),
            actor_slot: "slot_1".into(),
            template_id: "poison".into(),
            targets: vec!["slot_3".into()],
            grant_id: None,
        },
    )
    .await
    .expect("MU Poisoner submits poison");
    handle(
        &pool,
        &h,
        Command::ResolvePhase {
            game,
            seed: 707_101,
        },
    )
    .await
    .expect("host resolves MU poison mark");
    assert_eq!(
        slot_effects(&pool, game)
            .await
            .unwrap()
            .iter()
            .map(|effect| (effect.slot_id.as_str(), effect.effect.as_str()))
            .collect::<Vec<_>>(),
        vec![("slot_3", "poisoned")],
        "MU poison mark must project as a persistent effect"
    );
    let queued = delayed_death_queues(&pool, game).await.unwrap();
    assert_eq!(queued.len(), 1);
    assert_eq!(queued[0].queue_id, "poisoned:slot_3:mu_poison_n01");
    assert_eq!(queued[0].target_slot, "slot_3");
    assert_eq!(queued[0].cause, "poison");
    assert_eq!(queued[0].effect, "poisoned");
    assert_eq!(queued[0].source_slot, "slot_1");
    assert_eq!(queued[0].source_action, "mu_poison_n01");
    assert!(
        player_notifications(&pool, game)
            .await
            .unwrap()
            .iter()
            .any(|notice| notice.audience_slot == "slot_3"
                && notice.effect == "poisoned"
                && notice.status == "marked"),
        "target-visible MU poisoned mark should project a target notification"
    );

    let queued_before_cure = serde_json::to_string(&queued).unwrap();
    rebuild(&pool, game)
        .await
        .expect("Mafia Universe projection rebuild before cure consumes delayed death");
    assert_eq!(
        queued_before_cure,
        serde_json::to_string(&delayed_death_queues(&pool, game).await.unwrap()).unwrap(),
        "delayed_death_queue rebuild must preserve queued MU poison before cure"
    );

    handle(
        &pool,
        &h,
        Command::OpenDayPhase {
            game,
            phase: "N02".into(),
        },
    )
    .await
    .unwrap();
    handle(
        &pool,
        &user("mu_poison_user_2"),
        Command::SubmitAction {
            game,
            action_id: "mu_cure_n02".into(),
            actor_slot: "slot_2".into(),
            template_id: "cure_poison".into(),
            targets: vec!["slot_3".into()],
            grant_id: None,
        },
    )
    .await
    .expect("MU Poison Doctor submits cure");
    handle(
        &pool,
        &h,
        Command::ResolvePhase {
            game,
            seed: 707_102,
        },
    )
    .await
    .expect("host resolves MU poison cure");
    let cure_trace_payload = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionTrace' \
         AND payload->>'phase_id' = 'N02'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    let cure_trace = domain::validate_trace_json(&cure_trace_payload, domain::TRACE_VERSION)
        .expect("valid MU cure trace");
    assert_decision_trace(
        &cure_trace,
        DecisionTraceExpectation {
            stage: "night:pending_effect",
            source: "delayed_death:poisoned:slot_3:mu_poison_n01",
            outcome: "pending_poison_preempted_by_clear",
            detail: vec![
                ("target", serde_json::json!("slot_3")),
                ("effect", serde_json::json!("poisoned")),
                ("cause", serde_json::json!("poison")),
                ("source", serde_json::json!("slot_1")),
                ("source_action", serde_json::json!("mu_poison_n01")),
            ],
        },
    );
    assert!(
        slot_state(&pool, game)
            .await
            .unwrap()
            .iter()
            .find(|slot| slot.slot_id == "slot_3")
            .unwrap()
            .alive,
        "MU cure_poison must preempt pending poison death"
    );
    assert!(
        slot_effects(&pool, game).await.unwrap().is_empty(),
        "MU cure_poison must clear the persistent poisoned effect"
    );
    assert!(
        delayed_death_queues(&pool, game).await.unwrap().is_empty(),
        "MU cure_poison must consume the active delayed death queue"
    );

    handle(
        &pool,
        &h,
        Command::OpenDayPhase {
            game,
            phase: "N03".into(),
        },
    )
    .await
    .unwrap();
    handle(
        &pool,
        &user("mu_poison_user_1"),
        Command::SubmitAction {
            game,
            action_id: "mu_poison_n03".into(),
            actor_slot: "slot_1".into(),
            template_id: "poison".into(),
            targets: vec!["slot_4".into()],
            grant_id: None,
        },
    )
    .await
    .expect("MU Poisoner submits second poison");
    handle(
        &pool,
        &h,
        Command::ResolvePhase {
            game,
            seed: 707_103,
        },
    )
    .await
    .expect("host resolves second MU poison mark");
    let queued = delayed_death_queues(&pool, game).await.unwrap();
    assert_eq!(queued.len(), 1);
    assert_eq!(queued[0].queue_id, "poisoned:slot_4:mu_poison_n03");
    assert_eq!(queued[0].target_slot, "slot_4");
    assert_eq!(queued[0].source_action, "mu_poison_n03");

    let queued_before_death = serde_json::to_string(&queued).unwrap();
    rebuild(&pool, game)
        .await
        .expect("Mafia Universe projection rebuild before pending poison death");
    assert_eq!(
        queued_before_death,
        serde_json::to_string(&delayed_death_queues(&pool, game).await.unwrap()).unwrap(),
        "delayed_death_queue rebuild must preserve queued MU poison before death"
    );

    handle(
        &pool,
        &h,
        Command::OpenDayPhase {
            game,
            phase: "N04".into(),
        },
    )
    .await
    .unwrap();
    handle(
        &pool,
        &h,
        Command::ResolvePhase {
            game,
            seed: 707_104,
        },
    )
    .await
    .expect("host resolves MU pending poison death");
    let poison_trace_payload = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionTrace' \
         AND payload->>'phase_id' = 'N04'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    let poison_trace = domain::validate_trace_json(&poison_trace_payload, domain::TRACE_VERSION)
        .expect("valid MU pending poison trace");
    assert_decision_trace(
        &poison_trace,
        DecisionTraceExpectation {
            stage: "night:pending_effect",
            source: "delayed_death:poisoned:slot_4:mu_poison_n03",
            outcome: "pending_poison_applied",
            detail: vec![
                ("target", serde_json::json!("slot_4")),
                ("effect", serde_json::json!("poisoned")),
                ("cause", serde_json::json!("poison")),
                ("source", serde_json::json!("slot_1")),
                ("source_action", serde_json::json!("mu_poison_n03")),
            ],
        },
    );
    assert!(
        !slot_state(&pool, game)
            .await
            .unwrap()
            .iter()
            .find(|slot| slot.slot_id == "slot_4")
            .unwrap()
            .alive,
        "folded MU poisoned effect should kill on the pending poison phase"
    );
    assert!(
        delayed_death_queues(&pool, game).await.unwrap().is_empty(),
        "applied MU pending poison must consume the active delayed death queue"
    );

    let slots_before = serde_json::to_string(&slot_state(&pool, game).await.unwrap()).unwrap();
    let effects_before = serde_json::to_string(&slot_effects(&pool, game).await.unwrap()).unwrap();
    let queues_before =
        serde_json::to_string(&delayed_death_queues(&pool, game).await.unwrap()).unwrap();
    rebuild(&pool, game)
        .await
        .expect("Mafia Universe poison projection rebuild");
    assert_eq!(
        slots_before,
        serde_json::to_string(&slot_state(&pool, game).await.unwrap()).unwrap(),
        "slot_state rebuild must preserve MU delayed poison death"
    );
    assert_eq!(
        effects_before,
        serde_json::to_string(&slot_effects(&pool, game).await.unwrap()).unwrap(),
        "slot_effect rebuild must preserve MU poison/cure history"
    );
    assert_eq!(
        queues_before,
        serde_json::to_string(&delayed_death_queues(&pool, game).await.unwrap()).unwrap(),
        "delayed_death_queue rebuild must preserve consumed MU poison queues"
    );
    let cure_trace_after_rebuild = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionTrace' \
         AND payload->>'phase_id' = 'N02'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    let poison_trace_after_rebuild = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionTrace' \
         AND payload->>'phase_id' = 'N04'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    assert_eq!(
        cure_trace_payload, cure_trace_after_rebuild,
        "projection rebuild must not rewrite persisted MU cure trace envelope"
    );
    assert_eq!(
        poison_trace_payload, poison_trace_after_rebuild,
        "projection rebuild must not rewrite persisted MU pending poison trace envelope"
    );

    let audit = audit_resolution_envelopes(&pool, game)
        .await
        .expect("Mafia Universe poison resolution audit");
    assert!(
        audit.ok,
        "Mafia Universe poison resolution audit drifted: {audit:?}"
    );
}

