#[sqlx::test(migrations = "../projections/migrations")]
async fn host_resolve_phase_strong_willed_bypasses_roleblock(pool: PgPool) {
    let host = "host_h";
    let game = Uuid::new_v4();
    let h = user(host);

    handle(
        &pool,
        &h,
        Command::CreateGame {
            game,
            pack: "mafiascum".into(),
        },
    )
    .await
    .unwrap();
    for (slot, occupant, role) in [
        ("slot_1", "user_1", "mafia_goon"),
        ("slot_2", "user_2", "strong_willed_cop"),
        ("slot_3", "user_3", "roleblocker"),
        ("slot_4", "user_4", "vanilla_townie"),
    ] {
        handle(
            &pool,
            &h,
            Command::AddSlot {
                game,
                slot: slot.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignSlot {
                game,
                slot: slot.into(),
                user: occupant.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignRole {
                game,
                slot: slot.into(),
                role_key: role.into(),
            },
        )
        .await
        .unwrap();
    }
    handle(
        &pool,
        &h,
        Command::StartGame {
            game,
            phase: "N01".into(),
        },
    )
    .await
    .unwrap();

    handle(
        &pool,
        &user("user_3"),
        Command::SubmitAction {
            game,
            action_id: "block_strong_willed_n01".into(),
            actor_slot: "slot_3".into(),
            template_id: "roleblocker_block".into(),
            targets: vec!["slot_2".into()],
            grant_id: None,
        },
    )
    .await
    .expect("roleblocker submits block");
    handle(
        &pool,
        &user("user_2"),
        Command::SubmitAction {
            game,
            action_id: "strong_willed_check_n01".into(),
            actor_slot: "slot_2".into(),
            template_id: "strong_willed_investigate".into(),
            targets: vec!["slot_1".into()],
            grant_id: None,
        },
    )
    .await
    .expect("Strong-Willed Cop submits investigation");

    handle(&pool, &h, Command::ResolvePhase { game, seed: 7311 })
        .await
        .expect("host resolves StrongWilled suppression bypass");

    let applied_payload = resolution_payload(&pool, game, "N01", 7311).await;
    let applied = domain::validate_resolution_json(&applied_payload, domain::RESULT_VERSION)
        .expect("valid StrongWilled resolution");
    assert!(
        applied.events.iter().any(|indexed| matches!(
            &indexed.event,
            domain::InnerEvent::InvestigationResult {
                investigator,
                target,
                result,
                ..
            } if investigator == "slot_2"
                && target == "slot_1"
                && result == &serde_json::json!("scum")
        )),
        "Strong-Willed investigation should resolve despite the roleblock"
    );
    assert!(
        !applied.events.iter().any(|indexed| matches!(
            &indexed.event,
            domain::InnerEvent::ActionInterfered { actor, reason }
                if actor == "slot_2" && reason == "roleblocked"
        )),
        "Strong-Willed action must not emit roleblocked interference"
    );

    let trace_payload = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionTrace' \
         AND payload->>'phase_id' = 'N01'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    let trace = domain::validate_trace_json(&trace_payload, domain::TRACE_VERSION)
        .expect("valid StrongWilled trace");
    assert!(
        trace.decisions.iter().all(|decision| {
            decision.outcome != "action_suppressed" || decision.detail["actor"] != "slot_2"
        }),
        "Strong-Willed action must bypass standard-NAR suppression trace decisions"
    );

    let audit = audit_resolution_envelopes(&pool, game)
        .await
        .expect("StrongWilled resolution audit");
    assert!(audit.ok, "StrongWilled resolution audit drifted: {audit:?}");

    let slots_before = serde_json::to_string(&slot_state(&pool, game).await.unwrap()).unwrap();
    rebuild(&pool, game).await.expect("projection rebuild");
    assert_eq!(
        slots_before,
        serde_json::to_string(&slot_state(&pool, game).await.unwrap()).unwrap(),
        "slot_state rebuild should preserve StrongWilled resolution state"
    );
    let trace_after_rebuild = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionTrace' \
         AND payload->>'phase_id' = 'N01'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    assert_eq!(
        trace_payload, trace_after_rebuild,
        "projection rebuild must not rewrite persisted StrongWilled trace envelope"
    );
}

