async fn host_resolve_phase_emits_hammer_vote_outcome(pool: PgPool) {
    let game = Uuid::new_v4();
    let h = user("host_h");
    handle(
        &pool,
        &h,
        Command::CreateGame {
            game,
            pack: "test_hammer_majority".into(),
        },
    )
    .await
    .unwrap();
    for (slot, occupant, role) in [
        ("slot_1", "user_1", "vanilla_townie"),
        ("slot_2", "user_2", "vanilla_townie"),
        ("slot_3", "user_3", "mafia_goon"),
        ("slot_4", "user_4", "vanilla_townie"),
    ] {
        handle(
            &pool,
            &h,
            Command::AddSlot {
                game,
                slot: slot.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignSlot {
                game,
                slot: slot.into(),
                user: occupant.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &h,
            Command::AssignRole {
                game,
                slot: slot.into(),
                role_key: role.into(),
            },
        )
        .await
        .unwrap();
    }
    handle(
        &pool,
        &h,
        Command::StartGame {
            game,
            phase: "D01".into(),
        },
    )
    .await
    .unwrap();

    let vote_events: Vec<EventInput> = [
        ("slot_1", "slot_4"),
        ("slot_2", "slot_4"),
        ("slot_3", "slot_4"),
    ]
    .into_iter()
    .map(|(actor, target)| {
        EventInput::new(
            "VoteSubmitted",
            1,
            serde_json::json!({
                "phase_id": "D01",
                "actor": actor,
                "target": target
            }),
            ActorId::Slot(actor.into()),
            0,
        )
    })
    .collect();
    append_and_project(&pool, game, &vote_events)
        .await
        .expect("append hammer vote events");

    let ack = handle(&pool, &h, Command::ResolvePhase { game, seed: 74001 })
        .await
        .expect("host resolves hammer day");
    assert_eq!(
        ack.stream_seqs.len(),
        3,
        "hammer resolve appends ResolutionApplied, ResolutionTrace, and ThreadLocked"
    );

    let applied_payload = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionApplied' \
         AND payload->>'phase_id' = 'D01'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    let applied = domain::validate_resolution_json(&applied_payload, domain::RESULT_VERSION)
        .expect("hammer ResolutionApplied validates");
    let outcome = applied
        .events
        .iter()
        .find_map(|indexed| match &indexed.event {
            domain::InnerEvent::DayVoteOutcome(outcome) => Some(outcome),
            _ => None,
        })
        .expect("hammer day emits official vote outcome");
    assert_eq!(outcome.status, domain::VoteStatus::Hammer);
    assert_eq!(outcome.winner.as_deref(), Some("slot_4"));
    assert_eq!(outcome.tallies.get("slot_4"), Some(&3.0));
    assert_eq!(outcome.majority, Some(3.0));
    assert_eq!(outcome.votes.len(), 3);

    let slots = slot_state(&pool, game).await.unwrap();
    assert!(
        !slots
            .iter()
            .find(|slot| slot.slot_id == "slot_4")
            .unwrap()
            .alive,
        "hammer winner is lynched through projections"
    );

    let slots_before = serde_json::to_string(&slots).unwrap();
    rebuild(&pool, game).await.expect("projection rebuild");
    assert_eq!(
        slots_before,
        serde_json::to_string(&slot_state(&pool, game).await.unwrap()).unwrap(),
        "slot_state rebuild must preserve hammer lynch"
    );
}

