#[sqlx::test(migrations = "../projections/migrations")]
async fn changing_vote_overwrites_and_withdraw_removes(pool: PgPool) {
    let game = setup_game(&pool, "host_h", "slot_1", "user_a").await;
    for s in ["slot_2", "slot_3"] {
        handle(
            &pool,
            &user("host_h"),
            Command::AddSlot {
                game,
                slot: s.into(),
            },
        )
        .await
        .unwrap();
    }

    // A votes slot_2, then changes to slot_3 → only ONE ballot counts (overwrite).
    handle(
        &pool,
        &user("user_a"),
        Command::SubmitVote {
            game,
            actor_slot: "slot_1".into(),
            target: VoteTarget::Slot("slot_2".into()),
        },
    )
    .await
    .unwrap();
    assert_eq!(tally_for(&pool, game, "D01", "slot_2").await, 1);

    handle(
        &pool,
        &user("user_a"),
        Command::SubmitVote {
            game,
            actor_slot: "slot_1".into(),
            target: VoteTarget::Slot("slot_3".into()),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        tally_for(&pool, game, "D01", "slot_2").await,
        0,
        "overwritten"
    );
    assert_eq!(
        tally_for(&pool, game, "D01", "slot_3").await,
        1,
        "no double count"
    );

    // Withdraw removes the ballot entirely.
    handle(
        &pool,
        &user("user_a"),
        Command::WithdrawVote {
            game,
            actor_slot: "slot_1".into(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        tally_for(&pool, game, "D01", "slot_3").await,
        0,
        "withdrawn"
    );
}

#[sqlx::test(migrations = "../projections/migrations")]
async fn no_lynch_votes_resolve_to_official_engine_outcome(pool: PgPool) {
    let game = setup_game(&pool, "host_h", "slot_1", "user_1").await;
    for (slot, occupant, role) in [
        ("slot_2", "user_2", "vanilla_townie"),
        ("slot_3", "user_3", "mafia_goon"),
    ] {
        handle(
            &pool,
            &user("host_h"),
            Command::AddSlot {
                game,
                slot: slot.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &user("host_h"),
            Command::AssignSlot {
                game,
                slot: slot.into(),
                user: occupant.into(),
            },
        )
        .await
        .unwrap();
        handle(
            &pool,
            &user("host_h"),
            Command::AssignRole {
                game,
                slot: slot.into(),
                role_key: role.into(),
            },
        )
        .await
        .unwrap();
    }

    for (user_id, actor_slot) in [("user_1", "slot_1"), ("user_2", "slot_2")] {
        handle(
            &pool,
            &user(user_id),
            Command::SubmitVote {
                game,
                actor_slot: actor_slot.into(),
                target: VoteTarget::NoLynch,
            },
        )
        .await
        .unwrap();
    }
    assert_eq!(tally_for(&pool, game, "D01", "no_lynch").await, 2);

    handle(
        &pool,
        &user("host_h"),
        Command::ResolvePhase { game, seed: 9306 },
    )
    .await
    .expect("host resolves no-lynch day vote");

    let official = day_vote_outcomes(&pool, game)
        .await
        .expect("official day vote outcomes");
    assert_eq!(official.len(), 1);
    assert_eq!(official[0].phase_id, "D01");
    assert_eq!(official[0].status, "NoLynch");
    assert_eq!(official[0].winner_slot, None);
    assert_eq!(official[0].tallies["no_lynch"], serde_json::json!(2.0));
    assert_eq!(official[0].votes["slot_1"], "no_lynch");
    assert_eq!(official[0].votes["slot_2"], "no_lynch");

    let payload = sqlx::query_scalar::<_, serde_json::Value>(
        "SELECT payload FROM events WHERE stream_id = $1 AND kind = 'ResolutionApplied' \
         AND payload->>'phase_id' = 'D01'",
    )
    .bind(game)
    .fetch_one(&pool)
    .await
    .unwrap();
    let applied = domain::validate_resolution_json(&payload, domain::RESULT_VERSION).unwrap();
    assert!(
        applied.events.iter().all(|indexed| !matches!(
            &indexed.event,
            domain::InnerEvent::PlayerKilled { cause, .. } if cause == "day_vote"
        )),
        "NoLynch official outcome must not emit a day-vote death"
    );
}

// ───────────────────────── conflict surfacing ─────────────────────────

/// An eventstore `Conflict` surfaces — through the real pipeline `handle` — as
/// the retryable `Reject::StreamConflict`. We block the next stream slot with an
/// uncommitted concurrent append, then park the real `handle` call inside its
/// insert path until the conflicting row is committed. This proves the typed
/// retryable reject without relying on scheduler timing.
#[sqlx::test(migrations = "../projections/migrations")]
async fn conflict_surfaces_as_retryable_stream_conflict(pool: PgPool) {
    let game = setup_game(&pool, "host_h", "slot_1", "user_a").await;
    let lock_key = 41_004_i64;

    install_deadline_insert_blocker(&pool, game, lock_key).await;

    let mut conn_a = pool.acquire().await.unwrap();
    sqlx::query("SELECT pg_advisory_lock($1)")
        .bind(lock_key)
        .execute(&mut *conn_a)
        .await
        .unwrap();

    // tx_a holds an uncommitted append at the next stream_seq (base+1). It will
    // commit after the handler has computed the same base and reached its insert
    // path, so the handler collides on the UNIQUE constraint → typed Conflict.
    let mut tx_a = conn_a.begin().await.unwrap();
    eventstore::append_in_tx(
        &mut tx_a,
        game,
        &[eventstore::EventInput::new(
            "ThreadUnlocked",
            1,
            serde_json::json!({ "channel_id": "main" }),
            eventstore::ActorId::Host,
            0,
        )],
    )
    .await
    .unwrap();

    // The pipeline call (its own pool connection). The test trigger blocks it on
    // `pg_advisory_lock(lock_key)` immediately before its INSERT into `events`.
    // Once `pg_stat_activity` shows that wait, we know the handler already read
    // the stale stream max and is parked inside the append path.
    let pool2 = pool.clone();
    let handler = tokio::spawn(async move {
        handle(
            &pool2,
            &user("host_h"),
            Command::ExtendDeadline {
                game,
                phase: "D01".into(),
                at: 5,
            },
        )
        .await
    });

    wait_for_advisory_wait(&pool).await;
    tx_a.commit().await.unwrap();
    sqlx::query("SELECT pg_advisory_unlock($1)")
        .bind(lock_key)
        .execute(&mut *conn_a)
        .await
        .unwrap();

    let res = handler.await.unwrap();

    let err = res.expect_err("the racing handle must lose to tx_a");
    assert_eq!(
        err,
        Reject::StreamConflict,
        "Conflict → retryable StreamConflict"
    );
    assert!(err.is_retryable(), "the caller is told to reload + retry");
}

async fn install_deadline_insert_blocker(pool: &PgPool, game: Uuid, lock_key: i64) {
    let function_sql = format!(
        r#"
        CREATE OR REPLACE FUNCTION test_block_deadline_insert() RETURNS trigger AS $$
        BEGIN
            IF NEW.stream_id = '{game}'::uuid AND NEW.kind = 'DeadlineExtended' THEN
                PERFORM pg_advisory_lock({lock_key});
                PERFORM pg_advisory_unlock({lock_key});
            END IF;
            RETURN NEW;
        END;
        $$ LANGUAGE plpgsql;
        "#
    );
    sqlx::query(&function_sql).execute(pool).await.unwrap();
    sqlx::query("DROP TRIGGER IF EXISTS test_block_deadline_insert ON events")
        .execute(pool)
        .await
        .unwrap();
    sqlx::query(
        r#"
        CREATE TRIGGER test_block_deadline_insert
            BEFORE INSERT ON events
            FOR EACH ROW EXECUTE FUNCTION test_block_deadline_insert()
        "#,
    )
    .execute(pool)
    .await
    .unwrap();
}

async fn wait_for_advisory_wait(pool: &PgPool) {
    tokio::time::timeout(std::time::Duration::from_secs(5), async {
        loop {
            let waiting: bool = sqlx::query_scalar(
                r#"
                SELECT EXISTS (
                    SELECT 1
                    FROM pg_stat_activity
                    WHERE datname = current_database()
                      AND wait_event_type = 'Lock'
                      AND wait_event = 'advisory'
                )
                "#,
            )
            .fetch_one(pool)
            .await
            .unwrap();
            if waiting {
                break;
            }
            tokio::time::sleep(std::time::Duration::from_millis(5)).await;
        }
    })
    .await
    .expect("handler reached the advisory-lock gate before timing out");
}

// A trivial Ack sanity helper kept to ensure the type is exercised.
#[allow(dead_code)]
fn _ack_shape(a: &Ack) -> usize {
    a.stream_seqs.len()
}
